import React from "react";
import { Outlet, Link, useLocation } from "react-router-dom";
import { FileText, BarChart3, History, Building2, Home } from "lucide-react";

const Layout = () => {
  const location = useLocation();

  const navItems = [
    { path: "/", label: "Dashboard", icon: Home },
    { path: "/module-a", label: "Módulo A: Facturación", icon: FileText },
    { path: "/module-b", label: "Módulo B: Análisis Esp.", icon: BarChart3 },
    { path: "/history", label: "Historial", icon: History },
    { path: "/cost-centers", label: "Centros de Costo", icon: Building2 },
  ];

  return (
    <div className="flex min-h-screen bg-[#F4F4F5]">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-zinc-200">
        <div className="p-6 border-b border-zinc-200">
          <h1 className="font-heading text-xl font-bold text-[#09090B] tracking-tight">
            Data Extraction
          </h1>
          <p className="text-xs text-zinc-500 mt-1">Sistema Inteligente</p>
        </div>
        <nav className="p-4">
          {navItems.map((item) => {
            const Icon = item.icon;
            const isActive = location.pathname === item.path;
            return (
              <Link
                key={item.path}
                to={item.path}
                data-testid={`nav-${item.path.replace('/', '') || 'home'}`}
                className={`flex items-center gap-3 px-4 py-3 mb-1 rounded-none transition-colors ${
                  isActive
                    ? "bg-[#0033CC] text-white"
                    : "text-zinc-700 hover:bg-zinc-100"
                }`}
              >
                <Icon className="w-5 h-5" strokeWidth={1.5} />
                <span className="text-sm font-medium">{item.label}</span>
              </Link>
            );
          })}
        </nav>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col">
        {/* Top Header */}
        <header className="sticky top-0 bg-white border-b border-zinc-200 px-8 py-4 z-10">
          <div className="flex items-center justify-between">
            <h2 className="font-heading text-2xl font-bold text-[#09090B] tracking-tight">
              {navItems.find((item) => item.path === location.pathname)?.label || "Dashboard"}
            </h2>
            <div className="text-sm text-zinc-500">
              {new Date().toLocaleDateString('es-ES', { 
                weekday: 'long', 
                year: 'numeric', 
                month: 'long', 
                day: 'numeric' 
              })}
            </div>
          </div>
        </header>

        {/* Page Content */}
        <main className="flex-1 p-6 md:p-8">
          <Outlet />
        </main>
      </div>
    </div>
  );
};

export default Layout;
